1	/* Entry point for Capybara Delivery */
2	const canvas = document.getElementById('gameCanvas');
3	const ctx = canvas.getContext('2d');
4	
5	function resizeCanvas() {
6	  canvas.width = window.innerWidth;
7	  canvas.height = window.innerHeight;
8	}
9	
10	window.addEventListener('resize', resizeCanvas);
11	resizeCanvas();
12	
13	function gameLoop() {
14	  ctx.clearRect(0, 0, canvas.width, canvas.height);
15	  // Game logic goes here
16	  requestAnimationFrame(gameLoop);
17	}
18	
19	requestAnimationFrame(gameLoop);
