{"content":"* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}
html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #2d4a22;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}
#gameCanvas {
  display: block;
  width: 100%;
  height: 100%;
}
#hud {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  padding: 12px 24px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: rgba(0,0,0,0.5);
  color: #fff;
  font-size: 18px;
  font-weight: bold;
  pointer-events: none;
  z-index: 10;
}
.hud-item span {
  color: #ffd700;
}
#gameOver {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  background: rgba(0,0,0,0.7);
  z-index: 20;
}
.hidden {
  display: none !important;
}
.modal {
  background: #1a1a2e;
  padding: 40px 60px;
  border-radius: 16px;
  text-align: center;
  color: #fff;
  box-shadow: 0 0 30px rgba(255,215,0,0.3);
}
.modal h1 {
  font-size: 48px;
  margin-bottom: 16px;
  color: #ffd700;
}
.modal p {
  font-size: 24px;
  margin-bottom: 24px;
}
#restartBtn {
  padding: 12px 32px;
  font-size: 20px;
  border: none;
  border-radius: 8px;
  background: #ffd700;
  color: #1a1a2e;
  font-weight: bold;
  cursor: pointer;
  transition: transform 0.15s;
}
#restartBtn:hover {
  transform: scale(1.05);
}
